mapper.sql:
SELECT A.POPUP_NTC_ID , A.ORG_ID , A.POPUP_NTC_TTL , A.POPUP_NTC_CTS , A.POPUP_NTC_TYCD , A.POPUP_NTC_TRGT_CD , A.USEYN , A.POPUP_NTC_TDSTOP_USEYN , A.POPUP_NTC_TDSTOP_DAY_CNT , B.POPUP_WIN_WDTHSZ , B.POPUP_WIN_HGHT , B.POPUP_WIN_XCRD , B.POPUP_WIN_YCRD , B.POPUP_WIN_WDTH_RATIO , A.POPUP_NTC_SDTTM , A.POPUP_NTC_EDTTM , A.STTYEDU_ATNDLC_TRGTYN , A.SNGL_SESS_USEYN , A.RGTR_ID
, A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_POPUP_NTC A LEFT JOIN TB_LMS_POPUP_NTC_PSTN_SIZE B ON A.POPUP_NTC_ID = B.POPUP_NTC_ID WHERE A.ORG_ID = #{orgId}
AND A.USEYN = #{useyn}
AND A.USEYN = 'Y' AND FN_DTTM() BETWEEN A.POPUP_NTC_SDTTM AND A.POPUP_NTC_EDTTM
AND A.POPUP_NTC_TYCD = #{popupNtcTycd}
AND LOWER(A.POPUP_NTC_TRGT_CD) LIKE '%' || LOWER(#{item}) || '%'
AND SUBSTR(A.POPUP_NTC_SDTTM,1, 8) >= ${popupNtcSdttm}
AND SUBSTR(A.POPUP_NTC_EDTTM, 1, 8) <= ${popupNtcEdttm}
AND LOWER(A.POPUP_NTC_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))

