mapper.insert:
/*
	SQL ID : PopupManageDAO.insert
	설  명 : 팝업공지 등록
*/
INSERT INTO TB_LMS_POPUP_NTC (
	  POPUP_NTC_ID
	, ORG_ID
	, POPUP_NTC_TTL
	, POPUP_NTC_CTS
	, POPUP_NTC_TYCD
	, POPUP_NTC_TRGT_CD
	, USEYN
	, POPUP_NTC_TDSTOP_USEYN
	, POPUP_NTC_TDSTOP_DAY_CNT
	, POPUP_NTC_SDTTM
	, POPUP_NTC_EDTTM
	, STTYEDU_ATNDLC_TRGTYN
	, SNGL_SESS_USEYN
	, RGTR_ID
	, REG_DTTM
	, MDFR_ID
	, MOD_DTTM
) VALUES (
	  #{popupNtcId}
	, #{orgId}
	, #{popupNtcTtl}
	, #{popupNtcCts}
	, #{popupNtcTycd}
	, #{popupNtcTrgtCd}
	, #{useyn}
	, #{popupNtcTdstopUseyn}
	, #{popupNtcTdstopDayCnt}
	, #{popupNtcSdttm}
	, #{popupNtcEdttm}
	, #{sttyeduAtndlcTrgtyn}
	, #{snglSessUseyn}
	, #{rgtrId}
	, FN_DTTM()
	, #{mdfrId}
	, FN_DTTM()
)

mapper.update:
/*
	SQL ID : PopupManageDAO.update
	설  명 : 팝업공지 수정
*/
UPDATE TB_LMS_POPUP_NTC
SET 

	  POPUP_NTC_TTL = #{popupNtcTtl}
	, POPUP_NTC_CTS = #{popupNtcCts}
	, POPUP_NTC_TRGT_CD = #{popupNtcTrgtCd}
	, POPUP_NTC_SDTTM = #{popupNtcSdttm}
	, POPUP_NTC_EDTTM = #{popupNtcEdttm}
	, POPUP_NTC_TDSTOP_USEYN = #{popupNtcTdstopUseyn}
	, POPUP_NTC_TDSTOP_DAY_CNT = #{popupNtcTdstopDayCnt}
	, STTYEDU_ATNDLC_TRGTYN = #{sttyeduAtndlcTrgtyn}
	, SNGL_SESS_USEYN = #{snglSessUseyn}
	, USEYN = #{useyn}
	, MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
WHERE POPUP_NTC_ID = #{popupNtcId}
AND ORG_ID = #{orgId}

/*
	SQL ID : PopupManageDAO.updatePstnSize
	설  명 : 팝업공지 위치크기 수정
*/
UPDATE TB_LMS_POPUP_NTC_PSTN_SIZE
SET 
	  POPUP_WIN_WDTHSZ		=#{popupWinWdthsz}
	, POPUP_WIN_HGHT		=#{popupWinHght}
	, POPUP_WIN_WDTH_RATIO	=#{popupWinWdthRatio}
	, POPUP_WIN_HGHT_RATIO	=#{popupWinHghtRatio}
	, POPUP_WIN_XCRD		=#{popupWinXcrd}
	, POPUP_WIN_YCRD		=#{popupWinYcrd}
	, MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
WHERE POPUP_NTC_ID = #{popupNtcId}

/*
	SQL ID : PopupManageDAO.updateUseYn
	설  명 : 팝업공지 사용여부 수정
*/
UPDATE TB_LMS_POPUP_NTC
SET 
	  MDFR_ID = #{mdfrId}
	, USEYN = #{useyn}
WHERE POPUP_NTC_ID = #{popupNtcId}
AND ORG_ID = #{orgId}

mapper.delete:
/*
	SQL ID : PopupManageDAO.delete
	설  명 : 팝업공지 삭제
*/
DELETE FROM TB_LMS_POPUP_NTC
WHERE POPUP_NTC_ID = #{popupNtcId}
AND ORG_ID = #{orgId}
